mapper.select:
SELECT * FROM media_item 
WHERE user_id = #{userId} 
AND type = #{type}
AND status = #{status}
AND deleted = 0 
ORDER BY update_time DESC

SELECT * FROM media_item 
WHERE user_id != #{userId} 
AND deleted = 0 
AND id NOT IN 
    #{id}

AND (

        tags LIKE CONCAT('%', #{tag}, '%')

)
ORDER BY update_time DESC 
LIMIT #{limit}
